<template>
  <div>
    <h1 style="text-align: center;">{{ form.voteName }}</h1>
    <p style="text-align: center;">组织者：{{ form.organizer }}</p>
    <h2>未排名</h2>
    <pre>{{ result }}</pre>
    <h2>已排名</h2>
    <pre>{{ result }}</pre>
  </div>
</template>
<script>
import { voteBasicConfigurationDetail } from '@/api/voteBasicConfiguration'
import { getContestantScores, getContestantScoresRanked } from '@/api/dataAnalysis'
export default {
  data() {
    return {
      loading: false,
      form: {},
      result: null,
      resultRanked: null,
    }
  },
  mounted() {
    voteBasicConfigurationDetail({ id: this.$route.params.voteId }).then(res => {
      if (res) {
        this.form = res
      }
    }).finally(() => {
      this.loading = false
    })
    getContestantScores(this.$route.params.voteId).then(res => {
      this.result = res
    })
    getContestantScoresRanked(this.$route.params.voteId).then(res => {
      this.resultRanked = res
    })
  },
}
</script>
